import{_ as o,o as t,c as a,a5 as p}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"教程 0025：UPS C 固件骨架","description":"","frontmatter":{"title":"教程 0025：UPS C 固件骨架","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0025-ups-c-firmware-skeleton.html","status":"learning","visibility":"public","summary":"Imported from 0025-ups-c-firmware-skeleton.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0025-ups-c-firmware-skeleton.md","filePath":"content/power/lessons/0025-ups-c-firmware-skeleton.md","lastUpdated":null}'),i={name:"content/power/lessons/0025-ups-c-firmware-skeleton.md"};function l(c,e,s,r,d,n){return t(),a("div",null,[...e[0]||(e[0]=[p(`<h1 id="教程-0025-ups-c-固件骨架" tabindex="-1">教程 0025：UPS C 固件骨架 <a class="header-anchor" href="#教程-0025-ups-c-固件骨架" aria-label="Permalink to &quot;教程 0025：UPS C 固件骨架&quot;">​</a></h1><p>中文主讲。一个概念：把不间断电源（uninterruptible power supply / UPS）的模式状态机迁移成可编译、可阅读的小型 C 工程，训练从 Python 现象过渡到 C 模块边界。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学 C 代码和教学输入序列，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>UPS C 固件骨架（UPS C firmware skeleton）是把上一节的UPS 模式状态机（UPS mode state machine）拆成接近工程阅读方式的小型 C 工程。</p><p>本节只关注 C 工程骨架的模块边界：输入从哪里来、状态保存在哪里、输出许可在哪里集中生成。后续课程已经在同一项目目录继续叠加参数、保护、通信和保存模块，但本节先只用模式状态机这条主线读懂骨架。</p><p>inputs -&gt; mode_state_machine -&gt; outputs -&gt; main print</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>真实 UPS 工程不会只有一个控制公式。即使控制中断服务程序（control interrupt service routine / control ISR）里有模数转换器（analog-to-digital converter / ADC）采样和控制，系统级代码仍需要决定当前是在线模式、电池模式、旁路模式（bypass mode）还是故障模式。</p><p>在线模式通常会允许功率因数校正（power factor correction / PFC）和逆变脉宽调制（pulse-width modulation / PWM），电池模式会允许 DC-DC 和逆变 PWM，故障模式会关闭关键输出。用状态机（state machine）集中表达这些模式，比把判断散落在多个文件里更容易审查。</p><p>先看一个简化 C 骨架，后续读真实工程时就能沿着“输入、状态、输出许可”追踪，而不是在大量文件里迷路。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>Python 仿真像观察波形；C 骨架像看控制柜接线图。它不追求电路细节，而是回答：谁提供输入，谁决定模式，谁控制输出许可。</p><p>可以把它想成一组互锁开关：市电、电池、旁路同步和故障输入先进入状态判断；状态再决定 PFC、DC-DC、逆变 PWM 和旁路接触器能不能动作。故障锁存（fault latch）意味着故障不是输入一恢复就自动消失，而是需要安全条件和复位请求。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>核心状态机条件：</p><p>if (mains_ok) { mode = UPS_MODE_ONLINE; } else if (battery_ok) { mode = UPS_MODE_BATTERY; } else if (bypass_synchronized) { mode = UPS_MODE_BYPASS; } else { mode = UPS_MODE_FAULT; }</p><p>输出许可：</p><p>ONLINE -&gt; PFC=1, DC-DC=0, PWM=1, bypass=0 BATTERY -&gt; PFC=0, DC-DC=1, PWM=1, bypass=0 BYPASS -&gt; PFC=0, DC-DC=0, PWM=0, bypass=1 FAULT -&gt; PFC=0, DC-DC=0, PWM=0, bypass=0</p><p>这段逻辑不是最终工程策略，而是一个训练骨架：先看清模式到输出许可的最短链路，再逐步叠加保护、参数、通信和日志。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>本节的仿真任务分两步：先运行上一节 Python 模式状态机仿真，得到带图中参数框的 <code>simulations/results/ups_mode_state_machine.png</code>；再编译 C 骨架，对照同一条模式序列是否被 C 代码表达清楚。</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_mode_state_machine.py --no-open gcc -std=c99 -Wall -Wextra -Werror -I projects\\03-ups-c-firmware-skeleton\\src projects\\03-ups-c-firmware-skeleton\\src*.c -o projects\\03-ups-c-firmware-skeleton\\ups_c_firmware_skeleton.exe projects\\03-ups-c-firmware-skeleton\\ups_c_firmware_skeleton.exe</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_mode_state_machine.png</code>：图中参数框包含采样频率、仿真时长、各输入切换时刻、转移延时和最终模式；每条曲线都有图例。</p></li><li><p><code>projects/03-ups-c-firmware-skeleton/ups_c_firmware_skeleton.exe</code></p></li><li><p>终端输出：每个 tick 的 mode、fault、pfc、dcdc、inv_pwm、bypass。</p></li></ul><p>观察顺序：</p><ul><li><p><code>tick=00</code>：ONLINE，PFC 和逆变 PWM 允许。</p></li><li><p><code>tick=02</code>：BATTERY，DC-DC 和逆变 PWM 允许。</p></li><li><p><code>tick=04</code>：BYPASS，旁路接触器允许，逆变 PWM 关闭。</p></li><li><p><code>tick=06</code>：FAULT，所有输出关闭并故障锁存。</p></li><li><p><code>tick=08</code>：复位请求且市电恢复，回到 ONLINE。</p></li></ul><p>关键对照：Python 图帮助你看“模式随时间怎么变化”，C 输出帮助你看“工程文件如何生成同样的模式和输出许可”。例如终端中应能看到 <code>tick=00 mode=ONLINE</code> 和 <code>tick=08 mode=ONLINE</code>，说明故障复位路径被 C 骨架表达出来了。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>inputs.c</code>：教学输入序列，真实工程中对应采样、保护和同步判断结果。</p></li><li><p><code>mode_state_machine.c</code>：模式状态机和故障锁存。</p></li><li><p><code>outputs.c</code>：把模式转换成 PFC、DC-DC、PWM 和旁路接触器许可。</p></li><li><p><code>main.c</code>：教学主循环，真实工程可能由调度器或任务调用。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**C 工程只是 Python 脚本逐行翻译。 **纠正：**C 工程首先要表达模块边界、状态保存和输入输出责任。</p></li><li><p>**误解：**输出许可可以散落在各处。 **纠正：**入门时应尽量集中生成输出许可，便于审查状态机行为。</p></li><li><p>**误解：**故障恢复只看故障输入是否消失。 **纠正：**故障锁存通常需要复位请求和安全输入条件。</p></li><li><p>**误解：**现在项目目录里已经有参数、保护、通信等文件，所以 0025 必须一次学完所有模块。 **纠正：**0025 只抓 C 骨架主线，后续 0026 之后再逐个模块展开。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>。</p></li><li><p>能打开或查看 <code>simulations/results/ups_mode_state_machine.png</code>，并指出图中参数框和图例。</p></li><li><p>能解释 <code>UpsModeStateMachine_Step()</code> 的输入、状态和输出。</p></li><li><p>能解释 <code>UpsOutputs_FromMode()</code> 为什么集中生成许可。</p></li><li><p>能基于 C 文件准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p><code>tick=04</code> 为什么是 BYPASS，而不是继续 BATTERY？</p></li><li><p><code>tick=06</code> 进入 FAULT 后，为什么 PFC、DC-DC、inv_pwm、bypass 都是 0？</p></li><li><p>对照 <code>simulations/results/ups_mode_state_machine.png</code> 和 C 终端输出，哪一部分负责说明“时间顺序”，哪一部分负责说明“模块边界”？</p></li><li><p><code>mode_state_machine.c</code> 和 <code>outputs.c</code> 分开有什么好处？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>mode_state_machine.c -&gt; UpsModeStateMachine_Step()</code> 看到模式切换集中在一个函数。公司工程里模式状态机通常集中实现，还是分散在多个任务中？</p></li><li><p>我用 <code>outputs.c -&gt; UpsOutputs_FromMode()</code> 看到输出许可由模式统一生成。真实工程里 PFC、DC-DC、逆变 PWM 和旁路接触器许可通常在哪里统一仲裁？</p></li><li><p>教学代码里故障复位需要 <code>reset_request &amp;&amp; mains_ok</code>。真实工程里复位条件通常还会检查哪些状态？</p></li><li><p>我会只记录模块边界和公开可讨论的原则，不记录公司内部参数、内部通信协议、未公开故障码或客户项目数据。这样的提问边界是否合适？</p></li></ul><p>**下一步：**这个 C 骨架可以继续扩展参数表、通信帧、日志和更细的保护码；也可以转入三电平逆变器、Vienna 整流器和 LLC 的拓扑推导。</p><p>关联：<a href="./0024-ups-mode-state-machine.html">上一节：UPS 模式状态机</a>；源稿：<code>concepts/embedded/ups-c-firmware-skeleton.md</code>；项目：<code>projects/03-ups-c-firmware-skeleton</code>。</p><pre><code>上一节：教程 0024：UPS 模式状态机
下一节：教程 0026：UPS C 参数表
</code></pre>`,43)])])}const _=o(i,[["render",l]]);export{m as __pageData,_ as default};
